import React, { useState, useEffect } from 'react';
import './styles/global.css';
import './styles/App.css';
import UploadSection from './components/UploadSection';
import ResultsSection from './components/ResultsSection';
import BreedInfo from './components/BreedInfo';
import Chatbot from './components/Chatbot';
import { LeafIcon, SunIcon, MoonIcon } from './components/Icons';

const API_BASE = 'http://localhost:8000';

// API key is read from .env (REACT_APP_GEMINI_API_KEY)
// No UI for it — configured at build time
const GEMINI_KEY = process.env.REACT_APP_GEMINI_API_KEY || '';

export default function App() {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved || 'light';
  });

  const [file, setFile] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [uploadError, setUploadError] = useState('');

  const [predictions, setPredictions] = useState(null);
  const [isRejection, setIsRejection] = useState(false);
  const [rejectionMsg, setRejectionMsg] = useState('');

  const [breedName, setBreedName] = useState('');
  const [breedInfo, setBreedInfo] = useState(null);
  const [breedLoading, setBreedLoading] = useState(false);
  const [breedError, setBreedError] = useState('');
  const [showBreed, setShowBreed] = useState(false);

  const showResults = predictions !== null || isRejection;

  // Apply theme to document
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(t => t === 'light' ? 'dark' : 'light');

  const handleFileSelected = (f) => {
    setFile(f);
    setUploadError('');
    if (!f) {
      setPredictions(null);
      setIsRejection(false);
      setRejectionMsg('');
      setShowBreed(false);
      setBreedInfo(null);
    }
  };

  const handleClassify = async () => {
    if (!file) return;

    setIsLoading(true);
    setUploadError('');
    setPredictions(null);
    setIsRejection(false);
    setShowBreed(false);
    setBreedInfo(null);
    setBreedError('');

    try {
      const form = new FormData();
      form.append('file', file);

      const res = await fetch(`${API_BASE}/predict`, {
        method: 'POST',
        body: form,
      });

      if (res.status === 422) {
        const err = await res.json();
        setIsRejection(true);
        setRejectionMsg(err.detail || 'Image rejected by the detector.');
        return;
      }

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.detail || 'Prediction failed');
      }

      const data = await res.json();
      setPredictions(data.predictions);
      setBreedName(data.top_breed);

      if (GEMINI_KEY) {
        fetchBreedInfo(data.top_breed);
      }
    } catch (err) {
      setUploadError(`Error: ${err.message}. Make sure the backend is running on port 8000.`);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchBreedInfo = async (name) => {
    setShowBreed(true);
    setBreedLoading(true);
    setBreedError('');
    setBreedInfo(null);

    try {
      const res = await fetch(`${API_BASE}/breed-info`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ breed_name: name, api_key: GEMINI_KEY }),
      });
      const data = await res.json();
      if (!data.success) throw new Error(data.error);
      setBreedInfo(data.info);
    } catch (err) {
      setBreedError(`Could not load breed information: ${err.message}`);
    } finally {
      setBreedLoading(false);
    }
  };

  return (
    <div className="app">
      {/* ── Header ─────────────────────────────────────── */}
      <header className="header">
        <div className="header-brand">
          <div className="brand-mark">
            <LeafIcon size={15} />
          </div>
          <span className="brand-name">
            Bovine Classifier
            <span className="brand-tag"> · Indian Cattle AI</span>
          </span>
        </div>
        <div className="header-actions">
          <span className="model-chip">EfficientNet-B3 · 19 breeds</span>
          <button className="theme-toggle" onClick={toggleTheme} aria-label="Toggle theme">
            {theme === 'light' ? <MoonIcon /> : <SunIcon />}
          </button>
        </div>
      </header>

      {/* ── Main ───────────────────────────────────────── */}
      <main className="main">

        {/* Hero */}
        <section className="hero">
          <h1 className="hero-heading">
            Identify any Indian<br />
            <em>cattle breed instantly</em>
          </h1>
          <p className="hero-sub">
            Upload a photo of a cow or buffalo and our deep learning model will identify the breed with confidence scores.
          </p>
        </section>

        {/* Upload */}
        <section className="upload-section">
          <div className="section-label">Upload</div>
          <UploadSection
            onFileSelected={handleFileSelected}
            onClassify={handleClassify}
            isLoading={isLoading}
            hasFile={!!file}
            error={uploadError}
          />
        </section>

        {/* Results — only shown after prediction */}
        {showResults && (
          <>
            <div className="section-divider" />
            <section className="results-section">
              <div className="section-label">
                {isRejection ? 'Validation' : 'Result'}
              </div>
              <ResultsSection
                predictions={predictions}
                isRejection={isRejection}
                rejectionMessage={rejectionMsg}
              />
            </section>
          </>
        )}

        {/* Breed Info — only when available */}
        {showBreed && (
          <>
            <div className="section-divider" />
            <section className="breed-info-section">
              <div className="section-label">Breed Profile</div>
              <BreedInfo
                breedName={breedName}
                info={breedInfo}
                isLoading={breedLoading}
                error={breedError}
              />
            </section>
          </>
        )}

      </main>

      {/* ── Footer ─────────────────────────────────────── */}
      <footer className="footer">
        Bovine Breed Classifier · B.Tech Final Year Project · EfficientNet-B3 · 19 Indian Breeds
      </footer>

      {/* ── Floating Chatbot ────────────────────────────── */}
      <Chatbot apiKey={GEMINI_KEY} />
    </div>
  );
}
